// DEDUP CORE: take the FIRST pending item — never random, never repeats.
const gh = $input.first().json;
const queue = JSON.parse(Buffer.from(gh.content, 'base64').toString('utf8'));
const idx = queue.items.findIndex(i => i.status === 'pending');

// Queue empty => post NOTHING. Looping old content is what got the channel suppressed.
if (idx === -1) return [];

const item = queue.items[idx];
return [{ json: { item, itemIndex: idx, queue, sha: gh.sha } }];

// Mark the item posted and re-encode the queue for commit.
const { itemIndex, queue, sha, item } = $('Pick FIRST Pending (or stop)').first().json;
queue.items[itemIndex].status = 'posted';
queue.items[itemIndex].posted_at = new Date().toISOString();
const encoded = Buffer.from(JSON.stringify(queue, null, 2)).toString('base64');
return [{ json: { encoded, sha, postedTitle: item.title } }];
